      hint: 'import json, csv, uuid\nfrom datetime import datetime\ntask = {"id": str(uuid.uuid4())[:8], "title": title, "status": "todo", "created": datetime.now().isoformat()}\nтаблица: column widths через max(len(v) for v in column_values)\nпросроченные: datetime.fromisoformat(due_date) < datetime.now() and status != "done"\nfilter + sort: [t for t in tasks if ...]; sorted(filtered, key=...)',
      solution: 'import json\nimport csv\nimport uuid\nfrom datetime import datetime\nfrom pathlib import Path\n\nclass TaskManager:\n    def __init__(self, storage_path="tasks.json"):\n        self.storage_path = Path(storage_path)\n        self.tasks = []\n        self._load()\n\n    def _load(self):\n        if self.storage_path.exists():\n            try:\n                with open(self.storage_path, encoding="utf-8") as f:\n                    self.tasks = json.load(f)\n            except (json.JSONDecodeError, IOError):\n                self.tasks = []\n\n    def _save(self):\n        with open(self.storage_path, "w", encoding="utf-8") as f:\n            json.dump(self.tasks, f, ensure_ascii=False, indent=2)\n\n    def add(self, title, priority="medium", due_date=None, tags=None):\n        task = {\n            "id": str(uuid.uuid4())[:8],\n            "title": title,\n            "status": "todo",\n            "priority": priority,\n            "due_date": due_date,\n            "tags": tags or [],\n            "created": datetime.now().isoformat()\n        }\n        self.tasks.append(task)\n        self._save()\n        return task["id"]\n\n    def complete(self, task_id):\n        for task in self.tasks:\n            if task["id"] == task_id:\n                task["status"] = "done"\n                task["completed_at"] = datetime.now().isoformat()\n                self._save()\n                return True\n        return False\n\n    def delete(self, task_id):\n        before = len(self.tasks)\n        self.tasks = [t for t in self.tasks if t["id"] != task_id]\n        if len(self.tasks) < before:\n            self._save()\n            return True\n        return False\n\n    def list(self, filter_status=None, filter_priority=None, sort_by="created"):\n        filtered = self.tasks\n        if filter_status:\n            filtered = [t for t in filtered if t["status"] == filter_status]\n        if filter_priority:\n            filtered = [t for t in filtered if t["priority"] == filter_priority]\n        priority_order = {"high": 0, "medium": 1, "low": 2}\n        if sort_by == "priority":\n            filtered = sorted(filtered, key=lambda t: priority_order.get(t["priority"], 1))\n        elif sort_by == "due_date":\n            filtered = sorted(filtered, key=lambda t: t.get("due_date") or "9999")\n        else:\n            filtered = sorted(filtered, key=lambda t: t["created"])\n        return filtered\n\n    def search(self, query):\n        q = query.lower()\n        return [\n            t for t in self.tasks\n            if q in t["title"].lower() or any(q in tag.lower() for tag in t.get("tags", []))\n        ]\n\n    def stats(self):\n        now = datetime.now()\n        total = len(self.tasks)\n        done = sum(1 for t in self.tasks if t["status"] == "done")\n        overdue = sum(\n            1 for t in self.tasks\n            if t.get("due_date") and t["status"] != "done"\n            and datetime.fromisoformat(t["due_date"]) < now\n        )\n        by_priority = {p: sum(1 for t in self.tasks if t["priority"] == p) for p in ["high", "medium", "low"]}\n        return {"total": total, "done": done, "todo": total - done, "overdue": overdue, "by_priority": by_priority}\n\n    def format_table(self, tasks):\n        if not tasks:\n            return "Задач нет"\n        headers = ["ID", "Title", "Status", "Priority", "Due Date", "Tags"]\n        rows = [[\n            t["id"],\n            t["title"][:30],\n            t["status"],\n            t["priority"],\n            t.get("due_date", "-") or "-",\n            ",".join(t.get("tags", []))[:20]\n        ] for t in tasks]\n        widths = [max(len(str(r[i])) for r in [headers] + rows) for i in range(len(headers))]\n        separator = "-+-".join("-" * w for w in widths)\n        fmt = " | ".join(f"{{:<{w}}}" for w in widths)\n        lines = [fmt.format(*headers), separator]\n        for row in rows:\n            lines.append(fmt.format(*row))\n        return "\\n".join(lines)\n\n    def export_csv(self, filepath):\n        with open(filepath, "w", newline="", encoding="utf-8") as f:\n            if not self.tasks:\n                return 0\n            fields = ["id", "title", "status", "priority", "due_date", "tags", "created"]\n            writer = csv.DictWriter(f, fieldnames=fields)\n            writer.writeheader()\n            for task in self.tasks:\n                row = {k: task.get(k, "") for k in fields}\n                row["tags"] = ",".join(row["tags"]) if isinstance(row["tags"], list) else row["tags"]\n                writer.writerow(row)\n        return len(self.tasks)\n\n    def import_csv(self, filepath):\n        imported = 0\n        with open(filepath, newline="", encoding="utf-8") as f:\n            for row in csv.DictReader(f):\n                task = dict(row)\n                if isinstance(task.get("tags"), str):\n                    task["tags"] = [t for t in task["tags"].split(",") if t]\n                if not task.get("id"):\n                    task["id"] = str(uuid.uuid4())[:8]\n                self.tasks.append(task)\n                imported += 1\n        self._save()\n        return imported\n\n# Тест\nimport tempfile, os\nwith tempfile.NamedTemporaryFile(suffix=".json", delete=False) as f:\n    tmp = f.name\ntm = TaskManager(tmp)\nid1 = tm.add("Fix critical bug", priority="high", due_date="2024-01-01", tags=["python","bug"])\nid2 = tm.add("Write tests", priority="medium", tags=["python","testing"])\nid3 = tm.add("Update docs", priority="low", due_date="2024-12-31")\nid4 = tm.add("Deploy to prod", priority="high")\ntm.complete(id1)\ntm.complete(id3)\nall_tasks = tm.list()\nprint(tm.format_table(all_tasks))\nprint("\\nПоиск по \'python\':\')\nprint(tm.format_table(tm.search("python")))\nprint("\\nСтатистика:", tm.stats())\ncsv_path = tmp.replace(".json", ".csv")\ntm.export_csv(csv_path)\nprint(f"\\nЭкспортировано {len(all_tasks)} задач в CSV")\nos.unlink(tmp)\nos.unlink(csv_path)',
